import { Component } from '@angular/core';

@Component({
  selector: 'app-hello',          // used as <app-hello /> in templates
  standalone: true,               // no NgModule needed (Angular 17+)
  template: `
    <h1>Hello, {{ name }}!</h1>   <!-- {{ }} = interpolation -->
    <p>Welcome to Angular.</p>
  `,
})
export class HelloComponent {
  name = 'Angular';               // property bound to the template
}

import { bootstrapApplication } from '@angular/platform-browser';
import { appConfig } from './app/app.config';
import { App } from './app/app';

// bootstrapApplication() starts the Angular app.
// It takes the ROOT component and the app configuration.
bootstrapApplication(App, appConfig)
  .catch(err => console.error(err));
